DELETE FROM campo_subtarefas WHERE tarefa_id IN (SELECT t.id FROM campo_tarefas t JOIN campo_dias d ON d.id=t.dia_id WHERE d.evento_id IN (SELECT id FROM eventos WHERE nome='Playbook Desbravando (Modelo)'));
DELETE FROM campo_tarefas WHERE dia_id IN (SELECT id FROM campo_dias WHERE evento_id IN (SELECT id FROM eventos WHERE nome='Playbook Desbravando (Modelo)'));
DELETE FROM campo_dias WHERE evento_id IN (SELECT id FROM eventos WHERE nome='Playbook Desbravando (Modelo)');
